VALUES
  ('elementary-8b44517b-moex-00777', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '關於刑法上之故意犯與過失犯，下列敘述何者正確？', '["行為非出於故意者，即係出於過失", "間接故意犯與有認識過失犯之罪質相當", "刑法以處罰故意犯為原則，但過失犯情節嚴重者，仍應與故意犯同視", "過失犯之處罰以法律有明文者為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00778', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列有關刑法第138條侵害公務上掌管文書物品罪之敘述，何者錯誤？', '["甲收到法院寄發之傳票後，將之撕毀，甲成立本罪", "甲撕毀警員乙依法制作之談話筆錄，甲成立本罪", "甲與警員乙發生拉扯，致乙所穿制服毀損，甲不成立本罪", "警員乙將經扣押之物交由該物之所有權人甲暫時保管，甲故意將之毀損，甲成立本罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00779', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '刑法第17條因犯罪致發生一定之結果，而有加重其刑之規定者，如行為人不能預見其發生時，不適用之。 依實務見解，下列敘述何者錯誤？', '["必須行為人主觀上有預見結果發生", "本條在學理上稱為加重結果犯", "必須刑法條文有特別規定才有適用", "基礎犯罪與發生結果間須具備因果關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00780', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '行政程序法第3條第3項明列特定事項不適用該法之程序規定，下列何種行為即屬該法所定排除之事項？', '["內政部移民署依法禁止本國人出境", "高雄市警察局員警依據集會遊行法規定命令群眾立即解散", "國防部將部隊連級主官調任為內部單位參謀", "私立大學依據該校規定對特定學生為記過處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00781', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '我國憲法第23條規定：「以上各條列舉之自由權利，除為防止妨害他人自由、避免緊急危難、維持社會', '["比例原則", "法律保留原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00782', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '1989 年國小老師李幸長發起「無殼蝸牛運動」，夜宿臺北市忠孝東路，抗議政府漠視人民的居住權益。 後來，無住屋運動轉型為「崔媽媽基金會」，透過協助弱勢族群解決租屋問題，落實「居者適其屋」的 理念。關於「無殼蝸牛運動」發展到「崔媽媽基金會」之成立，下列敘述何者正確？', '["由非營利組織轉型為營利組織", "原強調利他主義後轉為主張利己導向", "原以公益為使命後轉為重視成本效益", "從倡議的社會運動轉為成立服務性的社團"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00783', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '近年來雙薪家庭比例上升，由於父母忙於工作，因此托兒所、安親班等機構成為安置孩童的重要處所。 根據統計，臺灣目前有政府立案的各種安親班、補習班、才藝班數量遠遠超過全臺超商數量。此現象說 明隨著社會變遷，家庭的何種功能正在轉變？', '["生育功能", "經濟功能", "社會化功能", "傳遞社會地位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00784', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '所謂「友善職場」，就是無歧視、重平等的職場。在職場中，勞工與雇主彼此尊重、合作，共同打造一 個性別平權的工作環境。下列何種作法，最有助於促進「友善職場」？', '["開放同志勞工因伴侶生病時可請家庭照顧假", "營造玻璃天花板環境以便落實性別實質平等", "健全性別職業隔離制度以保障女性就業機會", "降低女性勞動參與率以避免蠟燭兩頭燒現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00785', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '有關法律分類的敘述，下列何者正確？', '["民法：不成文法、私法、普通法、實體法", "民事訴訟法：成文法、私法、特別法、程序法", "刑事訴訟法：成文法、公法、普通法、程序法", "勞動基準法：不成文法、社會法、特別法、實體法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00786', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-b3f42868', 'sub-elementary-8b44517b-01', NULL, 'single_choice', '隨著高齡化社會的來臨，國際移工的身影已深入臺灣家庭，然而媒體總以「口音怪異、膚色黝黑、吵雜 或是忠誠度不足、常常逃跑」來形容移工的樣貌。由此可知，媒體主要是透過下列何種方式來影響閱聽 人的認知？', '["總白癡化", "置入性行銷", "暴力行為的複製", "形塑刻板印象與歧視"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
